/******
 * Calc to return = CQP_TOTAL_DOMESTIC_RDA_PERCENTAGE + CQP_TOTAL_DOMESTIC_RDT_PERCENTAGE
 * By Adriana Centellas
 * Edited By Natalia Mendez
 */

function safeNumber(v) {
  const n = parseFloat(v);
  return Number.isNaN(n) ? 0 : n;
}

return safeNumber(this.CQP_TOTAL_DOMESTIC_RDA_PERCENTAGE) + safeNumber(this.CQP_TOTAL_DOMESTIC_RDT_PERCENTAGE);

/******
 * Calc to return = CQP_TOTAL_DOMESTIC_GWD / CQP_TOTAL_DOMESTIC_ANNUAL_USD
 * By Adriana Centellas
 */

function safeNumber(v) {
  const n = parseFloat(v);
  return Number.isNaN(n) ? 0.00 : n;
}

return safeNumber((safeNumber(this.CQP_TOTAL_DOMESTIC_GWD) / safeNumber(this.CQP_TOTAL_DOMESTIC_ANNUAL_USD))) * 100;

/******
 * Calc to return = CQP_TOTAL_DOMESTIC_CIF_GWD + CQP_TOTAL_DOMESTIC_FOB_GWD + CQP_TOTAL_DOMESTIC_OI_GWD
