return safeNumber(this.CQP_TOTAL_DOMESTIC_RDA_GWD) + safeNumber(this.CQP_TOTAL_DOMESTIC_RDT_GWD);

/****
 * Calc to return = ((CQP_TOTAL_DOMESTIC_ANNUAL_USD / CQP_TOTAL_DOMESTIC_HISTORICAL)-1)*100
 * By Adriana Centellas
 * Edited By Natalia Mendez
 */

// Convert any value to a safe number
function safeNumber(v) {
  const n = parseFloat(v);
  return Number.isNaN(n) ? 0 : n;
}

// Ensure numeric values
let annualDomestic = safeNumber(this.CQP_TOTAL_DOMESTIC_ANNUAL_USD);
let historicalDomestic = safeNumber(this.CQP_TOTAL_DOMESTIC_HISTORICAL);

// Main calculation
var returnVar = (historicalDomestic !== 0 && annualDomestic !== 0)
  ? ((annualDomestic / historicalDomestic) - 1) * 100
  : 0;


// Remove classes first
setTimeout(function () {
  const inputSelector = $('[selector="CQP_TOTAL_DOMESTIC_VARIATION"] > div > input');
  inputSelector.removeClass('inputError inputOk');
}, 200);


// Only evaluate color if result is a valid number and not zero
if (!Number.isNaN(returnVar) && returnVar !== 0) {

  let valor = parseFloat(returnVar);

  setTimeout(function () {
    const inputSelector = $('[selector="CQP_TOTAL_DOMESTIC_VARIATION"] > div > input');
    inputSelector.removeClass('inputError inputOk');

    if (valor < 0) {
      inputSelector.addClass('inputError'); // red
    } else if (valor > 0) {
      inputSelector.addClass('inputOk'); // green
    }

  }, 500);
}

return returnVar;

