return safeNumber(this.CQP_TOTAL_DOMESTIC_RDT_ANNUAL_USD) * safeNumber((this.CQP_TOTAL_DOMESTIC_RDT_GROSS_RATE/100));

/****
 * Validate that if CQP_TOTAL_DOMESTIC_ANNUAL_USD has a value
 * (different from 0 or null), then at least one of the following fields
 * must also have a value:
 * CQP_TOTAL_DOMESTIC_RDA_PERCENTAGE or CQP_TOTAL_DOMESTIC_RDT_PERCENTAGE.
 *
 * Returns: { isValid: Boolean, message: String }
 * By Adriana Centellas
 * Edited By Natalia Mendez
 ****/

  // Parse numeric fields safely
  const annualUSD = parseFloat(this.CQP_TOTAL_DOMESTIC_ANNUAL_USD) || 0;
  const rdaPerc = parseFloat(this.CQP_TOTAL_DOMESTIC_RDA_PERCENTAGE) || 0;
  const rdtPerc = parseFloat(this.CQP_TOTAL_DOMESTIC_RDT_PERCENTAGE) || 0;

  // If there is no annual USD value, validation passes automatically
  if (annualUSD === 0) {
    return {
      isValid: true,
      message: ""
    };
  }

  // If annualUSD has value, at least one percentage must have a value
  const hasValidPercentage = rdaPerc !== 0 || rdtPerc !== 0;

  if (hasValidPercentage) {
    return {
      isValid: true,
      message: ""
    };
  } else {
    //If user wants to go back on the process the required values are now non required
      if (this.CQP_SUBMIT == "BACK") {
        return {
          isValid: true,
          message: ""
        };
      } else {
          return {
            isValid: false,
            message: "Since 'Total Domestic Transit Annual Mobilizations' has a value, at least one percentage (CIF, FOB, or OI) must also be filled."
          };
      }
    }

/*****
 * Validate that percentage equals 100 when total domestic annual USD is not 0 or null
 * By Adriana Centellas
 */

var total = this.CQP_TOTAL_DOMESTIC_ANNUAL_USD;
var percentage = this.CQP_TOTAL_DOMESTIC_PERCENTAGE;

// Normalize values to numbers
total = (total === null || total === undefined || isNaN(total)) ? 0 : Number(total);
percentage = (percentage === null || percentage === undefined || isNaN(percentage)) ? 0 : Number(percentage);

// Validation
if (total !== 0) {
  if (percentage !== 100) {
    return {
      isValid: false,
      message: "The Total Domestic Transit should be 100%"
    };
  }
}

// Default valid
return {
  isValid: true,
  message: ""
};
